24	// DefaultHeartbeatInterval is the nominal heartbeat cadence (ADR-007: 30s).
25	const DefaultHeartbeatInterval = 30 * time.Second
26	
27	// DefaultHeartbeatJitterFraction is applied to the interval as ±jitter so
28	// independent spokes do not synchronize their beats against one hub.
29	const DefaultHeartbeatJitterFraction = 0.25
30	
31	// DefaultDeregisterTimeout caps the best-effort deregister request on shutdown.
32	const DefaultDeregisterTimeout = 2 * time.Second
33	
34	// spokeStateFileName is the on-disk name for spoke-side state, used to detect
35	// URL changes across restarts so the spoke can re-register with a new URL.
36	const spokeStateFileName = "spoke-state.json"
37	
38	// SpokeState is the per-spoke persistent state. It records the URL last
39	// advertised to the hub and the stable identity_fingerprint generated on
40	// first start, both so URL changes can be detected across restarts and so
41	// re-registration can prove identity to the hub.
42	type SpokeState struct {
43		NodeID              string `json:"node_id"`
44		IdentityFingerprint string `json:"identity_fingerprint"`
45		LastURL             string `json:"last_url,omitempty"`
46	}
47	
48	// DefaultSpokeStatePath returns ~/.local/share/ddx/spoke-state.json (XDG aware).
49	func DefaultSpokeStatePath() (string, error) {
50		if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
51			return filepath.Join(xdg, "ddx", spokeStateFileName), nil
52		}
53		home, err := os.UserHomeDir()
54		if err != nil {
55			return "", fmt.Errorf("federation: cannot determine home directory: %w", err)
56		}
57		return filepath.Join(home, ".local", "share", "ddx", spokeStateFileName), nil
58	}
59	
60	// LoadSpokeState reads spoke state from path. Missing file → zero value.
61	func LoadSpokeState(path string) (*SpokeState, error) {
62		data, err := os.ReadFile(path)
63		if errors.Is(err, os.ErrNotExist) {
64			return &SpokeState{}, nil
65		}
66		if err != nil {
67			return nil, fmt.Errorf("federation: read spoke state: %w", err)
68		}
69		var st SpokeState
70		if err := json.Unmarshal(data, &st); err != nil {
71			// Corrupt file — start fresh; the caller will overwrite.
72			return &SpokeState{}, nil
73		}
74		return &st, nil
75	}
76	
77	// SaveSpokeState writes spoke state to path atomically (tmpfile+rename).
78	func SaveSpokeState(path string, st *SpokeState) error {
79		if st == nil {
80			return fmt.Errorf("federation: nil spoke state")
81		}
82		if err := os.MkdirAll(filepath.Dir(path), dirMode); err != nil {
83			return fmt.Errorf("federation: mkdir: %w", err)
84		}
85		data, err := json.MarshalIndent(st, "", "  ")
86		if err != nil {
87			return err
88		}
89		tmp, err := os.CreateTemp(filepath.Dir(path), ".spoke-state-*.json.tmp")
90		if err != nil {
91			return err
92		}
93		tmpPath := tmp.Name()
94		if _, err := tmp.Write(data); err != nil {
95			_ = tmp.Close()
96			_ = os.Remove(tmpPath)
97			return err
98		}
99		if err := tmp.Close(); err != nil {
100			_ = os.Remove(tmpPath)
101			return err
102		}
103		if err := os.Chmod(tmpPath, fileMode); err != nil {
104			_ = os.Remove(tmpPath)
105			return err
106		}
107		return os.Rename(tmpPath, path)
108	}
109	
110	// generateIdentityFingerprint returns a random 16-byte hex string. The
111	// fingerprint is generated once per node and persisted in spoke-state so a
112	// re-registration of the same node_id from the same machine is recognized
113	// as such (rather than rejected as a duplicate-identity conflict).
114	func generateIdentityFingerprint() string {
115		var buf [16]byte
116		if _, err := rand.Read(buf[:]); err != nil {
117			// Fall back to a hostname-derived value; collisions here are
118			// uninteresting because the hub's duplicate-id rejection only fires
119			// on a *different* fingerprint claiming the same node_id.
120			host, _ := os.Hostname()
121			return "fp-" + host
122		}
123		return "fp-" + hex.EncodeToString(buf[:])
124	}
