326	// register POSTs /api/federation/register to the hub.
327	func (s *Spoke) register(ctx context.Context) error {
328		body := federationRegisterRequest{
329			NodeID:               s.cfg.NodeID,
330			IdentityFingerprint:  s.identityFingerprint,
331			Name:                 s.cfg.Name,
332			URL:                  s.cfg.URL,
333			DDxVersion:           s.cfg.DDxVersion,
334			SchemaVersion:        s.cfg.SchemaVersion,
335			GraphQLSchemaVersion: s.cfg.GraphQLSchemaVersion,
336			Capabilities:         append([]string(nil), s.cfg.Capabilities...),
337		}
338		resp, err := s.postJSON(ctx, "/api/federation/register", body)
339		if err != nil {
340			return err
341		}
342		defer func() { _ = resp.Body.Close() }()
343		if resp.StatusCode < 200 || resp.StatusCode >= 300 {
344			buf, _ := io.ReadAll(resp.Body)
345			return fmt.Errorf("federation register: hub returned %d: %s", resp.StatusCode, string(buf))
346		}
347		s.mu.Lock()
348		s.registered = true
349		s.registeredCount++
350		s.mu.Unlock()
351		return nil
352	}
353	
354	// deregister DELETEs /api/federation/spokes/<id>.
355	func (s *Spoke) deregister(ctx context.Context) error {
356		u, err := s.hubURL("/api/federation/spokes/" + url.PathEscape(s.cfg.NodeID))
357		if err != nil {
358			return err
359		}
360		req, err := http.NewRequestWithContext(ctx, http.MethodDelete, u, nil)
361		if err != nil {
362			return err
363		}
364		resp, err := s.cfg.HTTPClient.Do(req)
365		if err != nil {
366			return err
367		}
368		defer func() { _ = resp.Body.Close() }()
369		_, _ = io.Copy(io.Discard, resp.Body)
370		// 404 is fine — nothing to deregister.
371		if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusNotFound {
372			return fmt.Errorf("federation deregister: hub returned %d", resp.StatusCode)
373		}
374		return nil
375	}
376	
377	// heartbeat POSTs /api/federation/heartbeat.
378	func (s *Spoke) heartbeat(ctx context.Context) error {
379		body := map[string]string{"node_id": s.cfg.NodeID}
380		resp, err := s.postJSON(ctx, "/api/federation/heartbeat", body)
381		if err != nil {
382			return err
383		}
384		defer func() { _ = resp.Body.Close() }()
385		_, _ = io.Copy(io.Discard, resp.Body)
386		if resp.StatusCode == http.StatusNotFound {
387			// Hub forgot us — re-register.
388			s.logf("federation: hub returned 404 on heartbeat; re-registering")
389			return s.register(ctx)
390		}
391		if resp.StatusCode < 200 || resp.StatusCode >= 300 {
392			return fmt.Errorf("federation heartbeat: hub returned %d", resp.StatusCode)
393		}
394		return nil
395	}
396	
397	// heartbeatLoop runs until ctx is canceled or Shutdown is called. Sleeps for
398	// HeartbeatInterval ± jitter between beats.
399	func (s *Spoke) heartbeatLoop(ctx context.Context) {
400		for {
401			d := s.nextHeartbeatDelay()
402			select {
403			case <-ctx.Done():
404				return
405			case <-s.stopped:
406				return
407			case <-time.After(d):
408			}
409			if err := s.heartbeat(ctx); err != nil {
410				s.mu.Lock()
411				s.hbErr = err
412				s.mu.Unlock()
413				s.logf("federation: heartbeat failed: %v", err)
414			} else {
415				s.mu.Lock()
416				s.hbErr = nil
417				s.heartbeatCount++
418				s.mu.Unlock()
419			}
420		}
421	}
422	
423	// NextHeartbeatDelay returns the next sleep duration the heartbeat loop will
424	// pick: HeartbeatInterval ± random jitter bounded by HeartbeatJitterFraction.
425	// Exposed so tests can verify jitter bounds without sleeping for 30s.
426	func (s *Spoke) NextHeartbeatDelay() time.Duration { return s.nextHeartbeatDelay() }
427	
428	// nextHeartbeatDelay returns interval ± random jitter in [0, jitter*interval].
429	func (s *Spoke) nextHeartbeatDelay() time.Duration {
430		base := s.cfg.HeartbeatInterval
431		jf := s.cfg.HeartbeatJitterFraction
432		if jf <= 0 {
433			return base
434		}
435		// Random offset in (-jf*base, +jf*base).
436		maxOffset := int64(float64(base) * jf)
437		if maxOffset <= 0 {
438			return base
439		}
440		n, err := rand.Int(rand.Reader, big.NewInt(2*maxOffset+1))
441		if err != nil {
442			return base
443		}
444		offset := n.Int64() - maxOffset
445		d := base + time.Duration(offset)
446		if d < 0 {
447			d = base
448		}
449		return d
450	}
451	
452	func (s *Spoke) hubURL(path string) (string, error) {
453		base := strings.TrimRight(s.cfg.HubURL, "/")
454		u, err := url.Parse(base + path)
455		if err != nil {
456			return "", err
457		}
458		return u.String(), nil
459	}
