461	func (s *Spoke) postJSON(ctx context.Context, path string, body any) (*http.Response, error) {
462		u, err := s.hubURL(path)
463		if err != nil {
464			return nil, err
465		}
466		buf, err := json.Marshal(body)
467		if err != nil {
468			return nil, err
469		}
470		req, err := http.NewRequestWithContext(ctx, http.MethodPost, u, bytes.NewReader(buf))
471		if err != nil {
472			return nil, err
473		}
474		req.Header.Set("Content-Type", "application/json")
475		return s.cfg.HTTPClient.Do(req)
476	}
