478	// federationRegisterRequest mirrors the hub-side request shape. Defined here
479	// to keep the federation package self-contained — the hub side
480	// (cli/internal/server/federation_hub.go) declares its own equivalent struct
481	// against the same wire contract.
482	type federationRegisterRequest struct {
483		NodeID               string   `json:"node_id"`
484		IdentityFingerprint  string   `json:"identity_fingerprint,omitempty"`
485		Name                 string   `json:"name"`
486		URL                  string   `json:"url"`
487		DDxVersion           string   `json:"ddx_version"`
488		SchemaVersion        string   `json:"schema_version"`
489		GraphQLSchemaVersion string   `json:"graphql_schema_version,omitempty"`
490		Capabilities         []string `json:"capabilities,omitempty"`
491	}
