	// reconcile owns stale). A spoke whose transport fails must.
	_, alive := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
